"""MKT John chapters 11-15."""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.write_text(json.dumps(data, ensure_ascii=False))
    print(f'  wrote {p.relative_to(ROOT)}')

JOHN = {
  "11": {
    "1": {"L":"Now a certain man was ill, Lazarus of Bethany, the village of Mary and her sister Martha.","M":"Now a man named Lazarus was sick. He was from Bethany, the village of Mary and her sister Martha.","T":"A man named Lazarus was sick. He lived in Bethany with his sisters Mary and Martha."},
    "2": {"L":"(It was Mary who anointed the Lord with ointment and wiped his feet with her hair, whose brother Lazarus was ill.)","M":"(This Mary, whose brother Lazarus now lay sick, was the same one who poured perfume on the Lord and wiped his feet with her hair.)","T":"(This was the same Mary who later anointed Jesus with perfume and wiped his feet with her hair. Her brother Lazarus was now sick.)"},
    "3": {"L":"Therefore the sisters sent to him, saying: 'Lord, behold, he whom you love is ill.'","M":"So the sisters sent word to Jesus, 'Lord, the one you love is sick.'","T":"So the sisters sent word to Jesus: 'Lord, your dear friend Lazarus is sick.'"},
    "4": {"L":"But when Jesus heard it he said: 'This sickness is not unto death, but for the glory of God, so that the Son of God may be glorified through it.'","M":"When he heard this, Jesus said, 'This sickness will not end in death. No, it is for God's glory so that God's Son may be glorified through it.'","T":"When Jesus heard this, he said, 'This illness will not end in death. It will bring glory to God, and through it the Son of God will be glorified.'"},
    "5": {"L":"Now Jesus loved Martha and her sister and Lazarus.","M":"Now Jesus loved Martha and her sister and Lazarus.","T":"Jesus loved Martha, her sister Mary, and Lazarus."},
    "6": {"L":"So when he heard that he was ill, he stayed two more days in the place where he was.","M":"So when he heard that Lazarus was sick, he stayed where he was two more days,","T":"Yet when he heard Lazarus was sick, he deliberately stayed where he was for two more days."},
    "7": {"L":"Then after this he says to the disciples: 'Let us go into Judea again.'","M":"and then he said to his disciples, 'Let us go back to Judea.'","T":"Then he said to his disciples, 'Let's go back to Judea.'"},
    "8": {"L":"The disciples say to him: 'Rabbi, the Jews were just now seeking to stone you, and you are going there again?'","M":"'But Rabbi,' they said, 'a short while ago the Jews there were trying to stone you, and yet you are going back?'","T":"His disciples objected, 'But Rabbi, the Jewish leaders just tried to stone you there! And you want to go back?'"},
    "9": {"L":"Jesus answered: 'Are there not twelve hours in the day? If anyone walks in the day, he does not stumble, because he sees the light of this world.'","M":"Jesus answered, 'Are there not twelve hours of daylight? Anyone who walks in the daytime will not stumble, for they see by this world's light.'","T":"Jesus replied, 'There are twelve hours of daylight each day. As long as it is light, a person can walk safely without stumbling.'"},
    "10": {"L":"'But if anyone walks in the night, he stumbles, because the light is not in him.'","M":"'It is when a person walks at night that they stumble, for they have no light.'","T":"'But when it is dark, people stumble because they can't see.'"},
    "11": {"L":"He said these things, and after this he says to them: 'Our friend Lazarus has fallen asleep; but I am going that I may awaken him.'","M":"After he had said this, he went on to tell them, 'Our friend Lazarus has fallen asleep; but I am going there to wake him up.'","T":"Then he told them plainly, 'Our friend Lazarus has fallen asleep. But I'm going there to wake him up.'"},
    "12": {"L":"The disciples therefore said to him: 'Lord, if he has fallen asleep, he will recover.'","M":"His disciples replied, 'Lord, if he sleeps, he will get better.'","T":"His disciples said, 'Lord, if he's sleeping, he'll get better on his own.'"},
    "13": {"L":"Now Jesus had spoken about his death, but they thought he was speaking of rest in sleep.","M":"Jesus had been speaking of his death, but his disciples thought he meant natural sleep.","T":"Jesus had meant that Lazarus had died, but they thought he was talking about actual sleep."},
    "14": {"L":"So then Jesus said to them plainly: 'Lazarus died.'","M":"So then he told them plainly, 'Lazarus is dead,'","T":"So Jesus told them directly: 'Lazarus is dead.'"},
    "15": {"L":"'And I rejoice for your sake that I was not there, so that you may believe. But let us go to him.'","M":"'and for your sake I am glad I was not there, so that you may believe. But let us go to him.'","T":"'And for your sake I'm glad I wasn't there, because now you will have the opportunity to believe. Let's go to him.'"},
    "16": {"L":"Therefore Thomas, called the Twin, said to his fellow disciples: 'Let us also go, that we may die with him.'","M":"Then Thomas (also known as Didymus) said to the rest of the disciples, 'Let us also go, that we may die with him.'","T":"Thomas, nicknamed the Twin, said to the other disciples, 'Let's go too—so we can die with him.'"},
    "17": {"L":"So when Jesus came, he found that he had already been in the tomb four days.","M":"On his arrival, Jesus found that Lazarus had already been in the tomb for four days.","T":"When Jesus arrived, he found that Lazarus had been in the tomb for four days already."},
    "18": {"L":"Now Bethany was near Jerusalem, about fifteen stadia away.","M":"Now Bethany was less than two miles from Jerusalem,","T":"Bethany was less than two miles from Jerusalem."},
    "19": {"L":"And many of the Jews had come to Martha and Mary to console them concerning their brother.","M":"and many Jews had come to Martha and Mary to comfort them in the loss of their brother.","T":"Many Jews had come from Jerusalem to comfort Martha and Mary in their grief."},
    "20": {"L":"Therefore Martha, when she heard that Jesus was coming, went to meet him; but Mary was sitting in the house.","M":"When Martha heard that Jesus was coming, she went out to meet him, but Mary stayed at home.","T":"When Martha heard Jesus was coming, she went out to meet him. Mary stayed home."},
    "21": {"L":"Martha therefore said to Jesus: 'Lord, if you had been here, my brother would not have died.'","M":"'Lord,' Martha said to Jesus, 'if you had been here, my brother would not have died.'","T":"Martha said to him, 'Lord, if you had been here, my brother wouldn't have died.'"},
    "22": {"L":"'Even now I know that whatever you ask of God, God will give you.'","M":"'But I know that even now God will give you whatever you ask.'","T":"'Even now I know that God will give you whatever you ask.'"},
    "23": {"L":"Jesus says to her: 'Your brother will rise again.'","M":"Jesus said to her, 'Your brother will rise again.'","T":"Jesus told her, 'Your brother will rise again.'"},
    "24": {"L":"Martha says to him: 'I know that he will rise again in the resurrection on the last day.'","M":"Martha answered, 'I know he will rise again in the resurrection at the last day.'","T":"Martha replied, 'Yes, I know he'll rise again in the resurrection on the last day.'"},
    "25": {"L":"Jesus said to her: 'I am the resurrection and the life. The one who believes in me, even if he dies, will live;'","M":"Jesus said to her, 'I am the resurrection and the life. The one who believes in me will live, even though they die;'","T":"Jesus said, 'I AM the resurrection and the life. Anyone who believes in me will live, even after dying.'"},
    "26": {"L":"'and everyone who lives and believes in me will never die—ever. Do you believe this?'","M":"'and whoever lives by believing in me will never die. Do you believe this?'","T":"'And everyone who lives and believes in me will never truly die. Do you believe this?'"},
    "27": {"L":"She says to him: 'Yes, Lord; I have believed that you are the Christ, the Son of God, the one coming into the world.'","M":"'Yes, Lord,' she replied, 'I believe that you are the Messiah, the Son of God, who is to come into the world.'","T":"'Yes, Lord,' she told him. 'I have always believed that you are the Messiah, the Son of God, the one who was promised to come into the world.'"},
    "28": {"L":"And having said this, she went off and called Mary her sister secretly, saying: 'The Teacher is here and is calling for you.'","M":"After she had said this, she went back and called her sister Mary aside. 'The Teacher is here,' she said, 'and is asking for you.'","T":"Then she quietly went back and pulled her sister Mary aside. 'The Teacher is here and wants to see you,' she whispered."},
    "29": {"L":"And when she heard this, she rose quickly and came to him.","M":"When Mary heard this, she got up quickly and went to him.","T":"Mary got up immediately and went to him."},
    "30": {"L":"Now Jesus had not yet come into the village, but was still in the place where Martha had met him.","M":"Now Jesus had not yet entered the village, but was still at the place where Martha had met him.","T":"Jesus hadn't yet entered the village—he was still at the spot where Martha had met him."},
    "31": {"L":"Therefore the Jews who were with her in the house, consoling her, when they saw that Mary rose up quickly and went out, followed her, thinking that she was going to the tomb to weep there.","M":"When the Jews who had been with Mary in the house, comforting her, noticed how quickly she got up and went out, they followed her, supposing she was going to the tomb to mourn there.","T":"When the Jews who were with Mary saw her get up quickly and go out, they followed her, thinking she was going to the tomb to weep."},
    "32": {"L":"Therefore when Mary came to where Jesus was, seeing him, she fell at his feet, saying to him: 'Lord, if you had been here, my brother would not have died.'","M":"When Mary reached the place where Jesus was and saw him, she fell at his feet and said, 'Lord, if you had been here, my brother would not have died.'","T":"When Mary reached Jesus and saw him, she fell at his feet. 'Lord,' she said, 'if you had been here, my brother wouldn't have died.'"},
    "33": {"L":"Therefore when Jesus saw her weeping, and the Jews who came with her also weeping, he was deeply moved in spirit and troubled himself,","M":"When Jesus saw her weeping, and the Jews who had come along with her also weeping, he was deeply moved in spirit and troubled.","T":"When Jesus saw her weeping, and the people with her weeping, he was deeply moved and troubled."},
    "34": {"L":"and said: 'Where have you laid him?' They say to him: 'Lord, come and see.'","M":"'Where have you laid him?' he asked. 'Come and see, Lord,' they replied.","T":"'Where have you laid him?' he asked. 'Come and see, Lord,' they said."},
    "35": {"L":"Jesus wept.","M":"Jesus wept.","T":"Jesus wept."},
    "36": {"L":"So the Jews were saying: 'See how much he loved him!'","M":"Then the Jews said, 'See how he loved him!'","T":"The people said, 'See how much he loved him!'"},
    "37": {"L":"But some of them said: 'Could not this man, who opened the eyes of the blind man, have prevented this man's death also?'","M":"But some of them said, 'Could not he who opened the eyes of the blind man have kept this man from dying?'","T":"But others said, 'This man opened the eyes of a blind person. Couldn't he have kept Lazarus from dying?'"},
    "38": {"L":"Therefore Jesus, again deeply moved within himself, comes to the tomb. Now it was a cave, and a stone lay against it.","M":"Jesus, once more deeply moved, came to the tomb. It was a cave with a stone laid across the entrance.","T":"Jesus, still deeply moved, arrived at the tomb. It was a cave with a large stone rolled across the entrance."},
    "39": {"L":"Jesus says: 'Remove the stone.' Martha, the sister of the one who had died, says to him: 'Lord, by now there is an odor, for he has been there four days.'","M":"'Take away the stone,' he said. 'But, Lord,' said Martha, the sister of the dead man, 'by this time there is a bad odor, for he has been there four days.'","T":"'Roll the stone away,' Jesus ordered. Martha objected, 'Lord, by now there will be a terrible smell—he's been dead four days!'"},
    "40": {"L":"Jesus says to her: 'Did I not say to you that if you believed, you would see the glory of God?'","M":"Then Jesus said, 'Did I not tell you that if you believe, you will see the glory of God?'","T":"Jesus replied, 'Didn't I tell you that if you would believe, you would see God's glory?'"},
    "41": {"L":"So they took away the stone. And Jesus lifted up his eyes and said: 'Father, I thank you that you have heard me.'","M":"So they took away the stone. Then Jesus looked up and said, 'Father, I thank you that you have heard me.'","T":"They rolled the stone away. Jesus looked up to heaven and said, 'Father, I thank you for hearing me.'"},
    "42": {"L":"'And I knew that you always hear me; but I said this because of the crowd standing here, so that they might believe that you sent me.'","M":"'I knew that you always hear me, but I said this for the benefit of the people standing here, that they may believe that you sent me.'","T":"'I know you always hear me. But I said this for the sake of the people standing here, so they will believe that you sent me.'"},
    "43": {"L":"And when he had said this, he cried out with a loud voice: 'Lazarus, come out!'","M":"When he had said this, Jesus called in a loud voice, 'Lazarus, come out!'","T":"Then he shouted, 'Lazarus, come out!'"},
    "44": {"L":"The one who had been dead came out, his hands and feet bound with strips of linen, and his face was bound with a cloth. Jesus says to them: 'Unbind him, and let him go.'","M":"The dead man came out, his hands and feet wrapped with strips of linen, and a cloth around his face. Jesus said to them, 'Take off the grave clothes and let him go.'","T":"The dead man came out—his hands and feet wrapped in burial cloth, and his face covered. Jesus told them, 'Unwrap him and let him go!'"},
    "45": {"L":"Therefore many of the Jews who had come to Mary and had seen what he did believed in him.","M":"Therefore many of the Jews who had come to visit Mary, and had seen what Jesus did, believed in him.","T":"Many of the Jews who had come with Mary and had seen what Jesus did put their faith in him."},
    "46": {"L":"But some of them went away to the Pharisees and told them what Jesus had done.","M":"But some of them went to the Pharisees and told them what Jesus had done.","T":"But some went to the Pharisees and reported what Jesus had done."},
    "47": {"L":"Therefore the chief priests and the Pharisees gathered the council and were saying: 'What are we doing? For this man is doing many signs.'","M":"Then the chief priests and the Pharisees called a meeting of the Sanhedrin. 'What are we accomplishing?' they asked. 'Here is this man performing many signs.'","T":"Then the chief priests and the Pharisees called an emergency session of the high council. 'What are we going to do?' they demanded. 'This man is performing many miraculous signs.'"},
    "48": {"L":"'If we leave him alone like this, all will believe in him, and the Romans will come and take away both our place and our nation.'","M":"'If we let him go on like this, everyone will believe in him, and then the Romans will come and take away both our temple and our nation.'","T":"'If we leave him alone, everyone will believe in him, and the Romans will come and destroy both our temple and our nation.'"},
    "49": {"L":"But a certain one of them, Caiaphas, being high priest that year, said to them: 'You know nothing at all,'","M":"Then one of them, named Caiaphas, who was high priest that year, spoke up, 'You know nothing at all!'","T":"One of them, Caiaphas, who was high priest that year, said with contempt, 'You don't know what you're talking about!'"},
    "50": {"L":"'nor do you consider that it is to your advantage that one man die on behalf of the people, and that the whole nation not perish.'","M":"'You do not realize that it is better for you that one man die for the people than that the whole nation perish.'","T":"'You're missing the obvious: it is better for one man to die for the people than for the whole nation to be destroyed.'"},
    "51": {"L":"Now he did not say this from himself, but being high priest that year he prophesied that Jesus was about to die for the nation;","M":"He did not say this on his own, but as high priest that year he prophesied that Jesus would die for the Jewish nation,","T":"He didn't say this on his own—as high priest that year, he was unknowingly prophesying that Jesus would die for the Jewish people."},
    "52": {"L":"and not for the nation only, but also so that the children of God who were scattered abroad he might gather into one.","M":"and not only for that nation but also for the scattered children of God, to bring them together and make them one.","T":"Not just for the Jewish nation, but to gather into one family all the scattered children of God."},
    "53": {"L":"So from that day on they took counsel to kill him.","M":"So from that day on they plotted to take his life.","T":"From that day on, they plotted to kill him."},
    "54": {"L":"Jesus therefore no longer went about openly among the Jews, but went from there into the region near the wilderness, to a city called Ephraim, and there he stayed with his disciples.","M":"Therefore Jesus no longer moved about publicly among the people of Judea. Instead he withdrew to a region near the wilderness, to a village called Ephraim, where he stayed with his disciples.","T":"So Jesus stopped traveling publicly. He withdrew to a town called Ephraim near the wilderness, where he stayed with his disciples."},
    "55": {"L":"Now the Passover of the Jews was near, and many went up from the country to Jerusalem before the Passover to purify themselves.","M":"When it was almost time for the Jewish Passover, many people went up from the country to Jerusalem for their ceremonial cleansing before the Passover.","T":"The Jewish Passover was approaching, and many people from the countryside came to Jerusalem early to go through the purification rituals before the festival."},
    "56": {"L":"They therefore were seeking Jesus and were saying to one another as they stood in the temple: 'What do you think? Surely he will not come to the feast, will he?'","M":"They kept looking for Jesus, and as they stood in the temple courts they asked one another, 'What do you think? Isn't he coming to the festival at all?'","T":"The people were looking for Jesus, asking each other as they stood in the temple courts, 'What do you think—will he actually come to the festival?'"},
    "57": {"L":"Now the chief priests and the Pharisees had given orders that if anyone knew where he was, he should report it, so that they might arrest him.","M":"But the chief priests and the Pharisees had given orders that anyone who found out where Jesus was should report it so that they might arrest him.","T":"The chief priests and Pharisees had issued orders that anyone knowing Jesus' whereabouts should report it so they could arrest him."}
  },

  "12": {
    "1": {"L":"Therefore Jesus, six days before the Passover, came to Bethany, where Lazarus was, whom Jesus had raised from the dead.","M":"Six days before the Passover, Jesus came to Bethany, where Lazarus lived, whom Jesus had raised from the dead.","T":"Six days before the Passover, Jesus arrived at Bethany—where Lazarus was, the man Jesus had raised from the dead."},
    "2": {"L":"So they made a supper for him there, and Martha was serving; and Lazarus was one of those reclining at the table with him.","M":"Here a dinner was given in Jesus' honor. Martha served, while Lazarus was among those reclining at the table with him.","T":"A dinner was given in Jesus' honor. Martha served, and Lazarus was one of those reclining at the table with him."},
    "3": {"L":"Then Mary, having taken a pound of costly perfume of pure nard, anointed the feet of Jesus and wiped his feet with her hair; and the house was filled with the fragrance of the perfume.","M":"Then Mary took about a pint of pure nard, an expensive perfume; she poured it on Jesus' feet and wiped his feet with her hair. And the house was filled with the fragrance of the perfume.","T":"Mary took a whole pound of very expensive perfume—pure nard—and poured it on Jesus' feet, wiping them with her hair. The fragrance filled the whole house."},
    "4": {"L":"But Judas Iscariot, one of his disciples—the one about to betray him—says:","M":"But one of his disciples, Judas Iscariot, who was later to betray him, objected,","T":"But Judas Iscariot—the disciple who would later betray Jesus—said,"},
    "5": {"L":"'Why was this perfume not sold for three hundred denarii and given to the poor?'","M":"'Why wasn't this perfume sold and the money given to the poor? It was worth a year's wages.'","T":"'Why wasn't this perfume sold for a year's wages and the money given to the poor?'"},
    "6": {"L":"He said this not because he cared for the poor, but because he was a thief, and having the money box, he used to pilfer what was put into it.","M":"He did not say this because he cared about the poor but because he was a thief; as keeper of the money bag, he used to help himself to what was put into it.","T":"He said this not because he cared about the poor—he was a thief who kept stealing from the group's money."},
    "7": {"L":"Therefore Jesus said: 'Leave her alone; she has kept it for the day of my burial.'","M":"'Leave her alone,' Jesus replied. 'It was intended that she should save this perfume for the day of my burial.'","T":"'Leave her alone,' Jesus said. 'She has kept this perfume for the day of my burial.'"},
    "8": {"L":"'For the poor you always have with you, but you do not always have me.'","M":"'You will always have the poor among you, but you will not always have me.'","T":"'You will always have the poor with you, but you will not always have me.'"},
    "9": {"L":"A large crowd of the Jews therefore learned that he was there, and they came not only because of Jesus but also to see Lazarus, whom he had raised from the dead.","M":"Meanwhile a large crowd of Jews found out that Jesus was there and came, not only because of him but also to see Lazarus, whom he had raised from the dead.","T":"Word spread that Jesus was there, and a large crowd came—not just to see Jesus but also to see Lazarus, the man he had raised from the dead."},
    "10": {"L":"But the chief priests resolved that they would kill Lazarus also,","M":"So the chief priests made plans to kill Lazarus as well,","T":"So the chief priests plotted to kill Lazarus too,"},
    "11": {"L":"because on account of him many of the Jews were leaving and believing in Jesus.","M":"for on account of him many of the Jews were going over to Jesus and believing in him.","T":"because his existence was causing many Jews to leave their leaders and put their faith in Jesus."},
    "12": {"L":"On the next day the large crowd that had come to the feast, having heard that Jesus was coming to Jerusalem,","M":"The next day the great crowd that had come for the festival heard that Jesus was on his way to Jerusalem.","T":"The next day the large crowd at the festival heard that Jesus was on his way to Jerusalem."},
    "13": {"L":"took the branches of palm trees and went out to meet him, and were crying out: 'Hosanna! Blessed is he who comes in the name of the Lord, the King of Israel!'","M":"They took palm branches and went out to meet him, shouting, 'Hosanna! Blessed is he who comes in the name of the Lord! Blessed is the king of Israel!'","T":"They took palm branches and went out to meet him, shouting, 'Hosanna! Blessed is the one who comes in the name of the Lord—the King of Israel!'"},
    "14": {"L":"And Jesus, having found a young donkey, sat on it; as it is written:","M":"Jesus found a young donkey and sat on it, as it is written:","T":"Jesus found a young donkey and rode on it, fulfilling the scripture:"},
    "15": {"L":"'Fear not, daughter of Zion; behold, your King is coming, seated on a donkey's colt.'","M":"'Do not be afraid, Daughter Zion; see, your king is coming, seated on a donkey's colt.'","T":"'Don't be afraid, daughter of Zion. See, your King is coming, riding on a young donkey.'"},
    "16": {"L":"His disciples did not understand these things at first; but when Jesus was glorified, then they remembered that these things had been written about him, and that they had done these things to him.","M":"At first his disciples did not understand all this. Only after Jesus was glorified did they realize that these things had been written about him and that these things had been done to him.","T":"His disciples didn't understand what was happening at the time. But after Jesus was raised to glory, they remembered and realized these scriptures had been fulfilled."},
    "17": {"L":"Therefore the crowd that had been with him when he called Lazarus out of the tomb and raised him from the dead was continuing to bear witness.","M":"Now the crowd that was with him when he called Lazarus from the tomb and raised him from the dead continued to spread the word.","T":"The crowd that had been present when Jesus called Lazarus from the tomb kept telling others about the miracle."},
    "18": {"L":"On this account also the crowd went to meet him, because they had heard that he had done this sign.","M":"Many people, because they had heard that he had performed this sign, went out to meet him.","T":"That was why so many went out to meet him—they had heard he had performed this miraculous sign."},
    "19": {"L":"The Pharisees therefore said to one another: 'You see that you are accomplishing nothing. Look—the world has gone after him.'","M":"So the Pharisees said to one another, 'See, this is getting us nowhere. Look how the whole world has gone after him!'","T":"The Pharisees said to each other in frustration, 'We're getting nowhere with this. Look—the whole world is following him!'"},
    "20": {"L":"Now there were some Greeks among those who were coming up to worship at the feast.","M":"Now there were some Greeks among those who went up to worship at the festival.","T":"Some Greeks who had come to Jerusalem for the Passover festival"},
    "21": {"L":"These therefore came to Philip, who was from Bethsaida of Galilee, and were asking him, saying: 'Lord, we want to see Jesus.'","M":"They came to Philip, who was from Bethsaida in Galilee, with a request. 'Sir,' they said, 'we would like to see Jesus.'","T":"went to Philip, who was from Bethsaida in Galilee. 'Sir,' they asked, 'we want to meet Jesus.'"},
    "22": {"L":"Philip comes and tells Andrew; Andrew and Philip come and tell Jesus.","M":"Philip went to tell Andrew; Andrew and Philip in turn told Jesus.","T":"Philip went to tell Andrew, and the two of them went to Jesus together."},
    "23": {"L":"And Jesus answers them, saying: 'The hour has come for the Son of Man to be glorified.'","M":"Jesus replied, 'The hour has come for the Son of Man to be glorified.'","T":"Jesus replied, 'The time has finally come for the Son of Man to enter his glory.'"},
    "24": {"L":"'Truly, truly I say to you, unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit.'","M":"'Truly, truly, I tell you, unless a kernel of wheat falls to the ground and dies, it remains only a single seed. But if it dies, it produces many seeds.'","T":"'I tell you the absolute truth: unless a seed falls into the earth and dies, it stays just a single seed. But when it dies, it produces a great harvest.'"},
    "25": {"L":"'The one who loves his life destroys it, and the one who hates his life in this world will keep it for eternal life.'","M":"'Anyone who loves their life will lose it, while anyone who hates their life in this world will keep it for eternal life.'","T":"'Whoever clings to their life will lose it, but whoever lets it go in this world will discover life that never ends.'"},
    "26": {"L":"'If anyone serves me, let him follow me; and where I am, there also will my servant be. If anyone serves me, the Father will honor him.'","M":"'Whoever serves me must follow me; and where I am, my servant also will be. My Father will honor the one who serves me.'","T":"'Anyone who wants to serve me must follow me, because my servants must be where I am. And my Father will honor anyone who serves me.'"},
    "27": {"L":"'Now my soul is troubled; and what shall I say? Father, save me from this hour? But for this very reason I came to this hour.'","M":"'Now my soul is troubled, and what shall I say? Father, save me from this hour? No, it was for this very reason I came to this hour.'","T":"'Right now I am deeply troubled. Should I ask the Father to save me from this moment? No—this is exactly what I came for.'"},
    "28": {"L":"'Father, glorify your name.' Therefore a voice came from heaven: 'I have glorified it and I will glorify it again.'","M":"'Father, glorify your name!' Then a voice came from heaven: 'I have glorified it, and will glorify it again.'","T":"'Father, bring glory to your name!' A voice from heaven replied, 'I have glorified it, and I will glorify it again.'"},
    "29": {"L":"The crowd therefore that was standing and heard was saying that it had thundered; others were saying: 'An angel has spoken to him.'","M":"The crowd that was there and heard it said it had thundered; others said an angel had spoken to him.","T":"The crowd standing nearby heard it and some thought it was thunder. Others said, 'An angel spoke to him.'"},
    "30": {"L":"Jesus answered and said: 'This voice has not come for my sake, but for yours.'","M":"Jesus said, 'This voice was for your benefit, not mine.'","T":"Jesus told them, 'That voice was not for my benefit—it was for yours.'"},
    "31": {"L":"'Now is the judgment of this world; now the ruler of this world will be cast out.'","M":"'Now is the time for judgment on this world; now the prince of this world will be driven out.'","T":"'The time of judgment for this world has come. The ruler of this world is about to be thrown out.'"},
    "32": {"L":"'And I, if I am lifted up from the earth, will draw all people to myself.'","M":"'And I, when I am lifted up from the earth, will draw all people to myself.'","T":"'And when I am lifted up from the earth, I will draw everyone to myself.'"},
    "33": {"L":"He was saying this to signify what kind of death he was about to die.","M":"He said this to show the kind of death he was going to die.","T":"He said this to indicate the kind of death he was going to die."},
    "34": {"L":"The crowd therefore answered him: 'We have heard from the Law that the Christ remains forever. How can you say that the Son of Man must be lifted up? Who is this Son of Man?'","M":"The crowd spoke up, 'We have heard from the Law that the Messiah will remain forever, so how can you say, The Son of Man must be lifted up? Who is this Son of Man?'","T":"The crowd called out, 'The Law says the Messiah will remain forever. How can you say the Son of Man must be lifted up? Who is this Son of Man you keep talking about?'"},
    "35": {"L":"Therefore Jesus said to them: 'The light is among you for a little while still. Walk while you have the light, so that darkness may not overtake you; and the one who walks in the darkness does not know where he is going.'","M":"Then Jesus told them, 'You are going to have the light just a little while longer. Walk while you have the light, before darkness overtakes you. Whoever walks in the dark does not know where they are going.'","T":"Jesus replied, 'The light is with you only a little while longer. Walk in the light while you have it, so darkness doesn't take you by surprise. When you walk in darkness, you don't know where you're going.'"},
    "36": {"L":"'While you have the light, believe in the light, so that you may become sons of light.' Jesus said these things, and going away he was hidden from them.","M":"'Believe in the light while you have the light, so that you may become children of light.' When he had finished speaking, Jesus left and hid himself from them.","T":"'While you still have the light, trust in the light—and become people of the light.' After saying this, Jesus slipped away and hid from them."},
    "37": {"L":"But though he had done so many signs before them, they were not believing in him,","M":"Even after Jesus had performed so many signs in their presence, they still would not believe in him.","T":"Even after all the miraculous signs he had done in their presence, most people still refused to believe in him."},
    "38": {"L":"so that the word of Isaiah the prophet might be fulfilled, which he said: 'Lord, who has believed our report? And to whom has the arm of the Lord been revealed?'","M":"This was to fulfill the word of Isaiah the prophet: 'Lord, who has believed our message and to whom has the arm of the Lord been revealed?'","T":"This fulfilled Isaiah's prophecy: 'Lord, who has believed our message? To whom has the Lord's power been revealed?'"},
    "39": {"L":"For this reason they were not able to believe, because Isaiah also said:","M":"For this reason they could not believe, because, as Isaiah says elsewhere:","T":"And they could not believe, because Isaiah also said:"},
    "40": {"L":"'He has blinded their eyes and hardened their heart, lest they see with their eyes and understand with their heart and turn, and I heal them.'","M":"'He has blinded their eyes and hardened their hearts, so they can neither see with their eyes, nor understand with their hearts, nor turn—and I would heal them.'","T":"'He has blinded their eyes and hardened their hearts, so that they cannot see with their eyes, understand with their hearts, or turn to me for healing.'"},
    "41": {"L":"Isaiah said these things because he saw his glory and spoke about him.","M":"Isaiah said this because he saw Jesus' glory and spoke about him.","T":"Isaiah said this because he saw Jesus' glory and spoke about him."},
    "42": {"L":"Nevertheless even of the rulers many believed in him; but because of the Pharisees they were not confessing it, so that they would not be put out of the synagogue.","M":"Yet at the same time many even among the leaders believed in him. But because of the Pharisees they would not openly acknowledge their faith for fear they would be put out of the synagogue;","T":"Yet even many of the Jewish leaders believed in him. But they wouldn't admit it because of the Pharisees—afraid they'd be expelled from the synagogue."},
    "43": {"L":"for they loved the glory of men more than the glory of God.","M":"for they loved human praise more than praise from God.","T":"They valued human approval more than God's approval."},
    "44": {"L":"But Jesus cried out and said: 'The one who believes in me does not believe in me, but in the one who sent me.'","M":"Then Jesus cried out, 'Whoever believes in me does not believe in me only, but in the one who sent me.'","T":"Jesus declared publicly, 'Anyone who believes in me is really believing in the one who sent me.'"},
    "45": {"L":"'And the one who sees me sees the one who sent me.'","M":"'The one who looks at me is seeing the one who sent me.'","T":"'And anyone who sees me sees the one who sent me.'"},
    "46": {"L":"'I have come as light into the world, so that everyone who believes in me should not remain in darkness.'","M":"'I have come into the world as a light, so that no one who believes in me should stay in darkness.'","T":"'I have come into the world as light, so that no one who trusts in me needs to remain in darkness.'"},
    "47": {"L":"'And if anyone hears my words and does not keep them, I do not judge him; for I came not to judge the world but to save the world.'","M":"'If anyone hears my words but does not keep them, I do not judge that person. For I did not come to judge the world, but to save the world.'","T":"'If anyone hears what I say and doesn't obey, I'm not the one who judges them. I came to save the world, not to judge it.'"},
    "48": {"L":"'The one who rejects me and does not receive my words has something that judges him: the word that I have spoken—that will judge him on the last day.'","M":"'There is a judge for the one who rejects me and does not accept my words; the very words I have spoken will condemn them at the last day.'","T":"'But anyone who rejects me and ignores my words has a judge—the very words I have spoken will judge them on the last day.'"},
    "49": {"L":"'Because I did not speak from myself, but the Father who sent me has himself given me a commandment—what to say and what to speak.'","M":"'For I did not speak on my own, but the Father who sent me commanded me to say all that I have spoken.'","T":"'I have not spoken on my own. The Father who sent me has commanded what to say and how to say it.'"},
    "50": {"L":"'And I know that his commandment is eternal life. Therefore what I speak—just as the Father has said to me, so I speak.'","M":"'I know that his command leads to eternal life. So whatever I say is just what the Father has told me to say.'","T":"'And I know his command leads to eternal life. So I say exactly what the Father told me to say.'"}
  },

  "13": {
    "1": {"L":"Now before the Feast of the Passover, Jesus knowing that his hour had come to pass from this world to the Father, having loved his own who were in the world, he loved them to the end.","M":"It was just before the Passover Festival. Jesus knew that the hour had come for him to leave this world and go to the Father. Having loved his own who were in the world, he loved them to the end.","T":"Before the Passover Festival, Jesus knew the time had come for him to leave this world and return to the Father. He had always loved his own, and he loved them completely to the very end."},
    "2": {"L":"And during supper—the devil having already put into the heart of Judas Iscariot, Simon's son, to betray him—","M":"The evening meal was in progress, and the devil had already prompted Judas, the son of Simon Iscariot, to betray Jesus.","T":"During supper—the devil having already planted the idea of betrayal in Judas' heart—"},
    "3": {"L":"Jesus, knowing that the Father had given all things into his hands, and that he had come from God and was going to God,","M":"Jesus knew that the Father had put all things under his power, and that he had come from God and was returning to God;","T":"knowing that the Father had placed everything in his hands and that he had come from God and was returning to God—"},
    "4": {"L":"rises from supper and lays aside his garments, and taking a towel he tied it around himself.","M":"so he got up from the meal, took off his outer clothing, and wrapped a towel around his waist.","T":"Jesus got up from the table, took off his outer robe, and wrapped a towel around his waist."},
    "5": {"L":"Then he pours water into the basin and began to wash the disciples' feet and to wipe them with the towel with which he was girded.","M":"After that, he poured water into a basin and began to wash his disciples' feet, drying them with the towel that was wrapped around him.","T":"He poured water into a basin and began washing his disciples' feet, drying them with the towel around his waist."},
    "6": {"L":"He comes therefore to Simon Peter. Peter says to him: 'Lord, are you washing my feet?'","M":"He came to Simon Peter, who said to him, 'Lord, are you going to wash my feet?'","T":"He came to Simon Peter, who said, 'Lord—you're going to wash my feet?'"},
    "7": {"L":"Jesus answered and said to him: 'What I am doing you do not know now, but you will understand after these things.'","M":"Jesus replied, 'You do not realize now what I am doing, but later you will understand.'","T":"Jesus told him, 'You don't understand what I'm doing right now, but you will later.'"},
    "8": {"L":"Peter says to him: 'You will never wash my feet—ever!' Jesus answered him: 'If I do not wash you, you have no part with me.'","M":"'No,' said Peter, 'you shall never wash my feet.' Jesus answered, 'Unless I wash you, you have no part with me.'","T":"'You'll never wash my feet!' Peter insisted. Jesus replied, 'If I don't wash you, you have no share in what I'm doing.'"},
    "9": {"L":"Simon Peter says to him: 'Lord, not my feet only, but also my hands and my head!'","M":"'Then, Lord,' Simon Peter replied, 'not just my feet but my hands and my head as well!'","T":"'Then don't stop at my feet, Lord!' Peter said. 'Wash my hands and my head too!'"},
    "10": {"L":"Jesus says to him: 'He who has bathed needs only to wash his feet, but is completely clean. And you are clean—but not all of you.'","M":"Jesus answered, 'Those who have had a bath need only to wash their feet; their whole body is clean. And you are clean, though not every one of you.'","T":"Jesus replied, 'A person who has already bathed only needs to wash their feet—the rest is clean. And you are clean—though not all of you.'"},
    "11": {"L":"For he knew the one who was betraying him; for this reason he said: 'Not all of you are clean.'","M":"For he knew who was going to betray him, and that was why he said not every one was clean.","T":"He said 'not all' because he knew who would betray him."},
    "12": {"L":"Therefore when he had washed their feet and put on his garments, he reclined again and said to them: 'Do you know what I have done to you?'","M":"When he had finished washing their feet, he put on his clothes and returned to his place. 'Do you understand what I have done for you?' he asked them.","T":"When he had finished, he put his robe back on and returned to his place. 'Do you understand what I just did for you?' he asked."},
    "13": {"L":"'You call me the Teacher and the Lord, and you say well, for so I am.'","M":"'You call me Teacher and Lord, and rightly so, for that is what I am.'","T":"'You call me Teacher and Lord—and you're right, because that's what I am.'"},
    "14": {"L":"'If then I, the Lord and the Teacher, washed your feet, you also ought to wash one another's feet.'","M":"'Now that I, your Lord and Teacher, have washed your feet, you also should wash one another's feet.'","T":"'So since I—your Lord and Teacher—have washed your feet, you must also wash each other's feet.'"},
    "15": {"L":"'For I gave you an example, so that just as I did to you, you also should do.'","M":"'I have set you an example that you should do as I have done for you.'","T":"'I have given you a model to follow: do for each other what I have done for you.'"},
    "16": {"L":"'Truly, truly I say to you, a slave is not greater than his master, nor is a messenger greater than the one who sent him.'","M":"'Truly, truly, I tell you, no servant is greater than his master, nor is a messenger greater than the one who sent him.'","T":"'I tell you the truth: a servant is not greater than the master, and a messenger is not greater than the one who sent them.'"},
    "17": {"L":"'If you know these things, you are blessed if you do them.'","M":"'Now that you know these things, you will be blessed if you do them.'","T":"'Now that you know these things, you will be blessed when you actually do them.'"},
    "18": {"L":"'I am not speaking of all of you; I know whom I chose; but so that the scripture may be fulfilled: He who eats bread with me lifted up his heel against me.'","M":"'I am not referring to all of you; I know those I have chosen. But this is to fulfill this passage of Scripture: He who shared my bread has turned against me.'","T":"'I'm not talking about all of you—I know the ones I chose. But scripture must be fulfilled: The one who shared my meal has turned against me.'"},
    "19": {"L":"'From now on I am telling you before it happens, so that when it happens you may believe that I am.'","M":"'I am telling you now before it happens, so that when it does happen you will believe that I am who I am.'","T":"'I'm telling you this now, before it happens, so that when it does happen you will believe that I AM.'"},
    "20": {"L":"'Truly, truly I say to you, the one who receives whomever I send receives me; and the one who receives me receives the one who sent me.'","M":"'Truly, truly, I tell you, whoever accepts anyone I send accepts me; and whoever accepts me accepts the one who sent me.'","T":"'I tell you the truth: whoever welcomes the person I send welcomes me, and whoever welcomes me welcomes the one who sent me.'"},
    "21": {"L":"Having said these things, Jesus was troubled in spirit and testified and said: 'Truly, truly I say to you, one of you will betray me.'","M":"After he had said this, Jesus was troubled in spirit and testified, 'Truly, truly, I tell you, one of you is going to betray me.'","T":"After saying this, Jesus was clearly troubled. 'I tell you the truth,' he said, 'one of you is going to betray me.'"},
    "22": {"L":"The disciples were looking at one another, at a loss as to which of them he was speaking.","M":"His disciples stared at one another, at a loss to know which of them he meant.","T":"The disciples looked at each other, completely at a loss about who he meant."},
    "23": {"L":"There was reclining on Jesus' bosom one of his disciples, whom Jesus loved.","M":"One of them, the disciple whom Jesus loved, was reclining next to him.","T":"One of the disciples—the one Jesus particularly loved—was reclining next to Jesus."},
    "24": {"L":"Therefore Simon Peter nods to this one and says to him: 'Ask who it is about whom he speaks.'","M":"Simon Peter motioned to this disciple and said, 'Ask him which one he means.'","T":"Simon Peter signaled to this disciple: 'Ask him who he means.'"},
    "25": {"L":"Therefore leaning back on Jesus' chest, he says to him: 'Lord, who is it?'","M":"Leaning back against Jesus, he asked him, 'Lord, who is it?'","T":"The disciple leaned close to Jesus and whispered, 'Lord, who is it?'"},
    "26": {"L":"Jesus therefore answers: 'It is the one for whom I will dip the piece of bread and give it to him.' So having dipped the piece of bread, he takes and gives it to Judas, the son of Simon Iscariot.","M":"Jesus answered, 'It is the one to whom I will give this piece of bread when I have dipped it in the dish.' Then, dipping the piece of bread, he gave it to Judas, the son of Simon Iscariot.","T":"Jesus replied, 'It is the one I give this bread to after I dip it.' He dipped the bread and gave it to Judas, son of Simon Iscariot."},
    "27": {"L":"And after the piece of bread, then Satan entered into him. Therefore Jesus says to him: 'What you do, do quickly.'","M":"As soon as Judas took the bread, Satan entered into him. So Jesus told him, 'What you are about to do, do quickly.'","T":"As soon as Judas took the bread, Satan entered him. Jesus said to him, 'Do what you're going to do, and do it quickly.'"},
    "28": {"L":"But no one of those reclining knew why he said this to him.","M":"But no one at the meal understood why Jesus said this to him.","T":"No one else at the table understood what Jesus meant."},
    "29": {"L":"For some were supposing, because Judas had the money box, that Jesus was saying to him: 'Buy what we need for the feast,' or that he should give something to the poor.","M":"Since Judas had charge of the money, some thought Jesus was telling him to buy what was needed for the festival, or to give something to the poor.","T":"Some thought Jesus was telling Judas to go buy what they needed for the festival, or to give something to the poor—since Judas kept the money."},
    "30": {"L":"Therefore having received the piece of bread, he immediately went out. And it was night.","M":"As soon as Judas had taken the bread, he went out. And it was night.","T":"As soon as Judas had taken the bread, he went out into the night."},
    "31": {"L":"Therefore when he had gone out, Jesus says: 'Now is the Son of Man glorified, and God is glorified in him.'","M":"When he was gone, Jesus said, 'Now the Son of Man is glorified and God is glorified in him.'","T":"When Judas had gone, Jesus said, 'Now the Son of Man is entering his glory, and God is glorified in him.'"},
    "32": {"L":"'If God is glorified in him, God will also glorify him in himself, and he will glorify him immediately.'","M":"'If God is glorified in him, God will glorify the Son in himself, and will glorify him at once.'","T":"'Since God is glorified in him, God will also glorify the Son—and he will do it very soon.'"},
    "33": {"L":"'Little children, yet a little while I am with you. You will seek me, and just as I said to the Jews: Where I am going you cannot come—so now I am saying to you.'","M":"'My children, I will be with you only a little longer. You will look for me, and just as I told the Jews, so I tell you now: Where I am going, you cannot come.'","T":"'My dear children, I will be with you only a little while longer. You will look for me—but just as I told the Jewish leaders, I now tell you: where I am going, you cannot come.'"},
    "34": {"L":"'A new commandment I give to you: that you love one another; just as I have loved you, that you also love one another.'","M":"'A new command I give you: Love one another. As I have loved you, so you must love one another.'","T":"'I am giving you a new command: love each other in the same way I have loved you.'"},
    "35": {"L":"'By this all will know that you are my disciples, if you have love for one another.'","M":"'By this everyone will know that you are my disciples, if you love one another.'","T":"'This is how everyone will know you are my disciples—by the love you show for each other.'"},
    "36": {"L":"Simon Peter says to him: 'Lord, where are you going?' Jesus answered him: 'Where I am going, you cannot follow now; but you will follow later.'","M":"Simon Peter asked him, 'Lord, where are you going?' Jesus replied, 'Where I am going, you cannot follow now, but you will follow later.'","T":"Simon Peter asked him, 'Lord, where are you going?' Jesus replied, 'You can't follow me now, but you will follow later.'"},
    "37": {"L":"Peter says to him: 'Lord, why can I not follow you right now? I will lay down my life for you.'","M":"Peter asked, 'Lord, why can't I follow you now? I will lay down my life for you.'","T":"Peter said, 'But why not, Lord? I'll give my life for you!'"},
    "38": {"L":"Jesus answers: 'Will you lay down your life for me? Truly, truly I say to you, the rooster will not crow until you have denied me three times.'","M":"Then Jesus answered, 'Will you really lay down your life for me? Truly, truly, I tell you, before the rooster crows, you will disown me three times!'","T":"Jesus answered, 'Will you really? I tell you the truth—before the rooster crows tonight, you will have denied me three times.'"}
  },

  "14": {
    "1": {"L":"'Let not your heart be troubled; you believe in God, believe also in me.'","M":"'Do not let your hearts be troubled. You believe in God; believe also in me.'","T":"'Don't be troubled. Trust in God, and trust in me.'"},
    "2": {"L":"'In my Father's house are many dwelling places; if it were not so, I would have told you. For I am going to prepare a place for you.'","M":"'My Father's house has many rooms; if that were not so, would I have told you that I am going there to prepare a place for you?'","T":"'There is more than enough room in my Father's house. If that weren't true, I would have told you, because I am going to prepare a place for you.'"},
    "3": {"L":"'And if I go and prepare a place for you, I will come again and will receive you to myself, so that where I am you also may be.'","M":"'And if I go and prepare a place for you, I will come back and take you to be with me that you also may be where I am.'","T":"'When everything is ready, I will come and take you to myself, so that where I am, you will also be.'"},
    "4": {"L":"'And where I am going, you know the way.'","M":"'You know the way to the place where I am going.'","T":"'And you know the way to where I am going.'"},
    "5": {"L":"Thomas says to him: 'Lord, we do not know where you are going; how do we know the way?'","M":"Thomas said to him, 'Lord, we don't know where you are going, so how can we know the way?'","T":"Thomas said, 'Lord, we don't even know where you're going! How can we know the way?'"},
    "6": {"L":"Jesus says to him: 'I am the way and the truth and the life; no one comes to the Father except through me.'","M":"Jesus answered, 'I am the way and the truth and the life. No one comes to the Father except through me.'","T":"Jesus told him, 'I am the way, the truth, and the life. No one can come to the Father except through me.'"},
    "7": {"L":"'If you have known me, you will know my Father also. From now on you do know him and have seen him.'","M":"'If you really know me, you will know my Father as well. From now on, you do know him and have seen him.'","T":"'If you really know me, you will know my Father as well. And from now on, you do know him—you have seen him.'"},
    "8": {"L":"Philip says to him: 'Lord, show us the Father, and it is sufficient for us.'","M":"Philip said, 'Lord, show us the Father and that will be enough for us.'","T":"Philip said, 'Lord, show us the Father—that's all we need!'"},
    "9": {"L":"Jesus says to him: 'Have I been with you so long, and you do not know me, Philip? The one who has seen me has seen the Father; how do you say: Show us the Father?'","M":"Jesus answered: 'Don't you know me, Philip, even after I have been among you such a long time? Anyone who has seen me has seen the Father. How can you say, Show us the Father?'","T":"Jesus answered, 'Philip, I've been with you all this time and you still don't know me? Anyone who has seen me has seen the Father! How can you say, Show us the Father?'"},
    "10": {"L":"'Do you not believe that I am in the Father and the Father is in me? The words that I say to you I do not speak from myself; but the Father who dwells in me does his works.'","M":"'Don't you believe that I am in the Father, and that the Father is in me? The words I say to you I do not speak on my own authority. Rather, it is the Father, living in me, who is doing his work.'","T":"'Don't you believe that I am in the Father and the Father is in me? The words I speak are not my own—the Father living in me is doing his own work.'"},
    "11": {"L":"'Believe me that I am in the Father and the Father is in me; or else believe because of the works themselves.'","M":"'Believe me when I say that I am in the Father and the Father is in me; or at least believe on the evidence of the works themselves.'","T":"'Just believe me when I say that I am in the Father and the Father is in me. Or at least believe because of the works you have seen.'"},
    "12": {"L":"'Truly, truly I say to you, the one who believes in me—the works that I do he will also do; and greater works than these he will do, because I am going to the Father.'","M":"'Truly, truly, I tell you, whoever believes in me will do the works I have been doing, and they will do even greater things than these, because I am going to the Father.'","T":"'I tell you the truth: anyone who believes in me will do the same works I've been doing—and even greater works, because I am going to the Father.'"},
    "13": {"L":"'And whatever you ask in my name, this I will do, so that the Father may be glorified in the Son.'","M":"'And I will do whatever you ask in my name, so that the Father may be glorified in the Son.'","T":"'You can ask for anything in my name, and I will do it, so the Son can bring glory to the Father.'"},
    "14": {"L":"'If you ask me anything in my name, I will do it.'","M":"'You may ask me for anything in my name, and I will do it.'","T":"'Yes, ask me for anything in my name, and I will do it!'"},
    "15": {"L":"'If you love me, you will keep my commandments.'","M":"'If you love me, keep my commands.'","T":"'If you love me, obey my commands.'"},
    "16": {"L":"'And I will ask the Father, and he will give you another Helper, so that he may be with you forever—'","M":"'And I will ask the Father, and he will give you another advocate to help you and be with you forever—'","T":"'And I will ask the Father, and he will give you another Advocate who will never leave you.'"},
    "17": {"L":"'the Spirit of truth, whom the world is not able to receive, because it neither sees him nor knows him; but you know him, because he remains with you and will be in you.'","M":"'the Spirit of truth. The world cannot accept him, because it neither sees him nor knows him. But you know him, for he lives with you and will be in you.'","T":"'This Advocate is the Spirit of truth. The world cannot receive him because it doesn't see or know him. But you know him, because he already lives with you and will be inside you.'"},
    "18": {"L":"'I will not leave you as orphans; I am coming to you.'","M":"'I will not leave you as orphans; I will come to you.'","T":"'I will not leave you like orphaned children—I am coming back to you.'"},
    "19": {"L":"'Yet a little while and the world no longer sees me, but you see me; because I live, you also will live.'","M":"'Before long, the world will not see me anymore, but you will see me. Because I live, you also will live.'","T":"'Before long, the world will not see me anymore, but you will see me. Because I live, you will live too.'"},
    "20": {"L":"'In that day you will know that I am in my Father, and you are in me, and I am in you.'","M":"'On that day you will realize that I am in my Father, and you are in me, and I am in you.'","T":"'When that day comes, you will understand that I am in my Father, you are in me, and I am in you.'"},
    "21": {"L":"'The one who has my commandments and keeps them—that is the one who loves me. And the one who loves me will be loved by my Father, and I will love him and will manifest myself to him.'","M":"'Whoever has my commands and keeps them is the one who loves me. The one who loves me will be loved by my Father, and I too will love them and show myself to them.'","T":"'The one who actually keeps my commands is the one who truly loves me. And whoever loves me will be loved by my Father, and I will love them and reveal myself to them.'"},
    "22": {"L":"Judas—not Iscariot—says to him: 'Lord, what has happened that you are about to reveal yourself to us and not to the world?'","M":"Then Judas (not Judas Iscariot) said, 'But, Lord, why do you intend to show yourself to us and not to the world?'","T":"Then Judas—not Judas Iscariot—asked him, 'Lord, why are you going to reveal yourself to us but not to the world?'"},
    "23": {"L":"Jesus answered and said to him: 'If anyone loves me, he will keep my word, and my Father will love him, and we will come to him and make our dwelling with him.'","M":"Jesus replied, 'Anyone who loves me will obey my teaching. My Father will love them, and we will come to them and make our home with them.'","T":"Jesus replied, 'Anyone who loves me will obey what I say. My Father will love them, and we will come and make our home with them.'"},
    "24": {"L":"'The one who does not love me does not keep my words; and the word that you hear is not mine, but the Father's who sent me.'","M":"'Anyone who does not love me will not obey my teaching. These words you hear are not my own; they belong to the Father who sent me.'","T":"'But anyone who doesn't love me won't obey me. And remember: these words are not mine—they come from the Father who sent me.'"},
    "25": {"L":"'These things I have spoken to you while remaining with you.'","M":"'All this I have spoken while still with you.'","T":"'I have told you all this while I'm still with you.'"},
    "26": {"L":"'But the Helper, the Holy Spirit, whom the Father will send in my name, that one will teach you all things and will remind you of all things that I said to you.'","M":"'But the Advocate, the Holy Spirit, whom the Father will send in my name, will teach you all things and will remind you of everything I have said to you.'","T":"'But the Advocate—the Holy Spirit, whom the Father will send in my name—will teach you everything and remind you of everything I have told you.'"},
    "27": {"L":"'Peace I leave with you; my peace I give to you. Not as the world gives do I give to you. Let not your heart be troubled, neither let it be afraid.'","M":"'Peace I leave with you; my peace I give you. I do not give to you as the world gives. Do not let your hearts be troubled and do not be afraid.'","T":"'I am leaving you with a gift—peace of mind and heart. The kind of peace I give isn't like anything the world offers. Don't be troubled or afraid.'"},
    "28": {"L":"'You heard that I said to you: I am going away and I am coming to you. If you loved me, you would have rejoiced that I am going to the Father, because the Father is greater than I.'","M":"'You heard me say, I am going away and I am coming back to you. If you loved me, you would be glad that I am going to the Father, for the Father is greater than I.'","T":"'You heard me say I'm going away and coming back to you. If you really loved me, you would be glad I'm going to the Father, because the Father is greater than I am.'"},
    "29": {"L":"'And now I have told you before it happens, so that when it does happen you may believe.'","M":"'I have told you now before it happens, so that when it does happen you will believe.'","T":"'I have told you this in advance so that when it happens, you will believe.'"},
    "30": {"L":"'I will no longer talk much with you, for the ruler of this world is coming, and he has no claim on me.'","M":"'I will not say much more to you, for the prince of this world is coming. He has no hold over me,'","T":"'I don't have much more time to talk with you, because the ruler of this world is coming. He has no power over me—'"},
    "31": {"L":"'but so that the world may know that I love the Father, and just as the Father commanded me, so I do. Arise, let us go from here.'","M":"'but he comes so that the world may learn that I love the Father and do exactly what my Father has commanded me. Come now; let us leave.'","T":"'but I do what the Father told me, so the world will know that I love the Father. Come, let us be going.'"}
  },

  "15": {
    "1": {"L":"'I am the true vine, and my Father is the vinedresser.'","M":"'I am the true vine, and my Father is the gardener.'","T":"'I am the true vine, and my Father is the gardener who tends it.'"},
    "2": {"L":"'Every branch in me that does not bear fruit he takes away; and every branch that bears fruit he prunes, so that it may bear more fruit.'","M":"'He cuts off every branch in me that bears no fruit, while every branch that does bear fruit he prunes so that it will be even more fruitful.'","T":"'He removes every branch in me that doesn't produce fruit. And he prunes the fruitful branches so they'll produce even more.'"},
    "3": {"L":"'You are already clean because of the word that I have spoken to you.'","M":"'You are already clean because of the word I have spoken to you.'","T":"'You are already clean because of the word I have spoken to you.'"},
    "4": {"L":"'Remain in me, and I in you. Just as the branch is not able to bear fruit from itself unless it remains in the vine, so neither can you unless you remain in me.'","M":"'Remain in me, as I also remain in you. No branch can bear fruit by itself; it must remain in the vine. Neither can you bear fruit unless you remain in me.'","T":"'Stay joined to me, and I will stay joined to you. A branch cannot produce fruit by itself—it has to stay on the vine. In the same way, you cannot produce fruit unless you remain in me.'"},
    "5": {"L":"'I am the vine; you are the branches. The one who remains in me and I in him—this one bears much fruit; because apart from me you are not able to do anything.'","M":"'I am the vine; you are the branches. If you remain in me and I in you, you will bear much fruit; apart from me you can do nothing.'","T":"'I am the vine; you are the branches. Those who remain in me and I in them will produce a great harvest. But apart from me, you can do nothing.'"},
    "6": {"L":"'If anyone does not remain in me, he is thrown out like a branch and dries up; and they gather them and throw them into the fire, and they are burned.'","M":"'If you do not remain in me, you are like a branch that is thrown away and withers; such branches are picked up, thrown into the fire and burned.'","T":"'Those who don't remain in me are like branches that are cut off and wither. Such branches are gathered up, thrown into the fire, and burned.'"},
    "7": {"L":"'If you remain in me and my words remain in you, ask whatever you wish and it will be done for you.'","M":"'If you remain in me and my words remain in you, ask whatever you wish, and it will be done for you.'","T":"'But if you remain in me and my words remain in you, you may ask for anything you want, and it will be granted!'"},
    "8": {"L":"'In this my Father is glorified: that you bear much fruit, and so you will be my disciples.'","M":"'This is to my Father's glory, that you bear much fruit, showing yourselves to be my disciples.'","T":"'When you produce a great harvest, my Father receives glory, and this proves you are my true disciples.'"},
    "9": {"L":"'Just as the Father has loved me, I also have loved you; remain in my love.'","M":"'As the Father has loved me, so have I loved you. Now remain in my love.'","T":"'The Father has loved me deeply, and I love you in exactly the same way. Stay inside that love.'"},
    "10": {"L":"'If you keep my commandments, you will remain in my love, just as I have kept my Father's commandments and remain in his love.'","M":"'If you keep my commands, you will remain in my love, just as I have kept my Father's commands and remain in his love.'","T":"'When you obey my commands, you remain in my love—just as I have obeyed my Father's commands and remain in his love.'"},
    "11": {"L":"'These things I have spoken to you so that my joy may be in you and your joy may be made full.'","M":"'I have told you this so that my joy may be in you and that your joy may be complete.'","T":"'I have told you this so that my joy can be your joy too—a joy that fills you completely.'"},
    "12": {"L":"'This is my commandment: that you love one another as I have loved you.'","M":"'My command is this: Love each other as I have loved you.'","T":"'This is my command: Love each other in the same way I have loved you.'"},
    "13": {"L":"'Greater love than this no one has: that one lay down his life for his friends.'","M":"'Greater love has no one than this: to lay down one's life for one's friends.'","T":"'The greatest love in the world is shown when someone gives their life for their friends.'"},
    "14": {"L":"'You are my friends if you do what I command you.'","M":"'You are my friends if you do what I command.'","T":"'You are my friends when you do what I command.'"},
    "15": {"L":"'No longer do I call you slaves, because the slave does not know what his master is doing; but I have called you friends, because all things that I heard from my Father I have made known to you.'","M":"'I no longer call you servants, because a servant does not know his master's business. Instead, I have called you friends, for everything that I learned from my Father I have made known to you.'","T":"'I no longer call you servants, because a servant doesn't know what their master is planning. I call you friends, because I have shared with you everything the Father told me.'"},
    "16": {"L":"'You did not choose me, but I chose you and appointed you so that you should go and bear fruit—and your fruit should remain—so that whatever you ask the Father in my name, he may give you.'","M":"'You did not choose me, but I chose you and appointed you so that you might go and bear fruit—fruit that will last—and so that whatever you ask in my name the Father will give you.'","T":"'You didn't choose me. I chose you. I appointed you to go and produce lasting fruit, so that the Father will give you whatever you ask for in my name.'"},
    "17": {"L":"'These things I command you: that you love one another.'","M":"'This is my command: Love each other.'","T":"'Here is my command: Love each other.'"},
    "18": {"L":"'If the world hates you, know that it has hated me before you.'","M":"'If the world hates you, keep in mind that it hated me first.'","T":"'If the world hates you, remember that it hated me first.'"},
    "19": {"L":"'If you were of the world, the world would love its own; but because you are not of the world, but I chose you out of the world, for this reason the world hates you.'","M":"'If you belonged to the world, it would love you as its own. As it is, you do not belong to the world, but I have chosen you out of the world. That is why the world hates you.'","T":"'If you belonged to the world system, the world would love you. But you don't—I chose you out of the world—so the world hates you.'"},
    "20": {"L":"'Remember the word that I said to you: A slave is not greater than his master. If they persecuted me, they will also persecute you; if they kept my word, they will keep yours also.'","M":"'Remember what I told you: A servant is not greater than his master. If they persecuted me, they will persecute you also. If they obeyed my teaching, they will obey yours also.'","T":"'Remember what I told you: servants are not greater than their master. Since they persecuted me, they will persecute you too. And if they had obeyed me, they would obey you.'"},
    "21": {"L":"'But all these things they will do to you on account of my name, because they do not know the one who sent me.'","M":"'They will treat you this way because of my name, for they do not know the one who sent me.'","T":"'They will treat you this way because of who you follow—they don't know the one who sent me.'"},
    "22": {"L":"'If I had not come and spoken to them, they would not have sin; but now they have no excuse for their sin.'","M":"'If I had not come and spoken to them, they would not be guilty of sin; but now they have no excuse for their sin.'","T":"'If I hadn't come and spoken to them, they wouldn't be responsible for their sin. But now they have no excuse.'"},
    "23": {"L":"'The one who hates me also hates my Father.'","M":"'Whoever hates me hates my Father as well.'","T":"'Anyone who hates me also hates my Father.'"},
    "24": {"L":"'If I had not done among them the works that no one else did, they would not have sin; but now they have both seen and hated me and my Father.'","M":"'If I had not done among them the works no one else did, they would not be guilty of sin. As it is, they have seen, and yet they have hated both me and my Father.'","T":"'If I hadn't done miraculous works among them that no one else had ever done, they wouldn't be guilty. But they have seen these things, and still they have hated both me and my Father.'"},
    "25": {"L":"'But so that the word written in their Law might be fulfilled: They hated me without cause.'","M":"'But this is to fulfill what is written in their Law: They hated me without reason.'","T":"'But this is the fulfillment of what is written in their own scriptures: They hated me for no reason.'"},
    "26": {"L":"'When the Helper comes, whom I will send to you from the Father—the Spirit of truth who proceeds from the Father—that one will testify about me.'","M":"'When the Advocate comes, whom I will send to you from the Father—the Spirit of truth who goes out from the Father—he will testify about me.'","T":"'But when the Advocate comes—the Spirit of truth who comes from the Father, and whom I will send to you—he will testify about me.'"},
    "27": {"L":"'And you also testify, because you have been with me from the beginning.'","M":"'And you also must testify, for you have been with me from the beginning.'","T":"'And you must also testify, because you have been with me from the very beginning.'"}
  }
}

def merge_tier(existing, new_data, tier_key):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, tiers in verses.items():
            existing[ch][v] = tiers[tier_key]

for tier, key in [('literal','L'), ('mediating','M'), ('thought','T')]:
    data = load(tier, 'john')
    merge_tier(data, JOHN, key)
    save(tier, 'john', data)

print('\nJohn 11–15 written. Chapters covered:', sorted(JOHN.keys(), key=int))
